#include <iostream>
#include <string>
#include <sstream>
#include <iomanip>
#include <cmath>

// This driver demonstrates how to read input and format output
// for a single test case, reflecting the expected interaction.
int main() {
    double radius;
    if (!(std::cin >> radius)) {
        std::cerr << "Invalid input for radius." << std::endl;
        return 1;
    }

    const double PI_VAL = 3.14159;
    double area = PI_VAL * radius * radius;
    double perimeter = 2 * PI_VAL * radius;

    std::cout << std::fixed << std::setprecision(4) << "Area: " << area << std::endl;
    std::cout << std::fixed << std::setprecision(4) << "Perimeter: " << perimeter << std::endl;

    return 0;
}
